{"command": "python -c "
from datasets import load_dataset
import json

ds = load_dataset('ryanmarten/OpenThoughts-1k-sample', split='train')

# Search for science-related content and check if the response appears to be from DeepSeek
science_samples = []

science_keywords = ['chemistry', 'physics', 'biology', 'science', 'quantum', 'atom', 'molecule', 'reaction', 'DNA', 'cell', 'force', 'energy']

for i, item in enumerate(ds):
    text = str(item).lower()

    # Check if science-related
    is_science = any(keyword in text for keyword in science_keywords)

    if is_science:
        science_samples.append(i)

if science_samples:
    print(f'Found {len(science_samples)} science-related samples')
    print('First few science sample indices:', science_samples[:5])

    # Show a science sample
    if len(science_samples) > 0:
        idx = science_samples[0]
        sample = ds[idx]
        print(f'\n=== Science sample {idx} ===')
        for conv in sample['conversations']:
            if 'value' in conv:
                value = conv['value']
                if len(value) > 300:
                    print(f'{conv.get(\"from\")}: {value[:300]}...')
                else:
                    print(f'{conv.get(\"from\")}: {value}')
else:
    print('No science-related samples found')
"
", "description": "Search for science-related samples"}

